args.sparql:
SELECT ?series ?seriesLabel ?duration WHERE {
  ?series wdt:P31 wd:Q482043;
          wdt:P27 wd:Q30;
          wdt:P571 ?start.
  OPTIONAL { ?series wdt:P576 ?end. }
  BIND(YEAR(STRDT(?start, xsd:date)) AS ?start_year)
  BIND(IF(BOUND(?end), YEAR(STRDT(?end, xsd:date)), 2023) AS ?end_year)
  BIND(?end_year - ?start_year AS ?duration)
  ?series rdfs:label ?seriesLabel.
  FILTER(LANG(?seriesLabel) = "en")
} ORDER BY DESC(?duration) LIMIT 5

